VALUES
  ('bookkeeper-moex-00187', 'bookkeeper', 'bookkeeper-moex-113-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依據營利事業所得稅查核準則，有關收入的查核，下列敘述何者正確？', '["營利事業國外進、銷貨，其入帳匯率與結匯匯率變動所產生之收益，應調整其外銷收入或進料、進 貨成本", "營利事業銷售貨物或勞務，如有隨銷售附贈禮券、獎勵積點或保固服務等，該附贈部分相對應的收 入認列應予以遞延", "外銷貨物應列為外銷貨物報關日所屬會計年度之銷貨收入處理", "營利事業分期付款之銷貨，其當期損益得依全部毛利法、毛利百分比法與普通銷貨法擇一計算。所 有產品同期分期付款銷貨損益均應採用同一計算方式，不得中途變更"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:19+00:00", "source_pdf_sha1": "1b22e5321747", "answer_pdf_sha1": "27d2bd6acd46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00188', 'bookkeeper', 'bookkeeper-moex-113-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '根據加值型及非加值型營業稅法之規定，下列何種情形非屬營業稅課徵範圍？', '["營業人解散時，將餘存貨物分配予股東", "外銷貨物", "進口貨物", "由國外進入科學園區內之園區事業的保稅貨物"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:19+00:00", "source_pdf_sha1": "1b22e5321747", "answer_pdf_sha1": "27d2bd6acd46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00189', 'bookkeeper', 'bookkeeper-moex-113-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '下列有關銷售貨物或勞務營業稅徵免之敘述，何者正確？', '["與外銷有關之勞務，或在國內提供而在國外使用之勞務，非屬我國營業稅課徵範圍，免徵營業稅", "銷售予免稅出口區外銷廠商之生產設備，適用零稅率，其進項稅額得申請扣抵及退稅", "依法設立之免稅商店銷售與過境或出境旅客之貨物，適用免稅優惠，無銷項稅額，亦不得申請進項 稅額扣抵及退稅", "醫院、診所、療養院提供之醫療勞務、藥品、病房之住宿及膳食，屬一般銷售貨物及勞務，應課徵 營業稅，但若為財團法人者，可申請減半徵收"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:19+00:00", "source_pdf_sha1": "1b22e5321747", "answer_pdf_sha1": "27d2bd6acd46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00190', 'bookkeeper', 'bookkeeper-moex-113-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '國內個人消費者透過網路向在我國境內無固定營業場所之線上訂房平台業者(境外電商)購買之訂房勞 務，有關該項勞務收入之營業稅規定，下列何者正確？', '["應課徵營業稅，由該線上訂房平台業者依法申報繳納營業稅", "應課徵營業稅，由該國內個人消費者依法申報繳納營業稅", "非屬境內銷售勞務，不課徵營業稅", "適用零稅率，國內個人消費者可申請退稅"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:19+00:00", "source_pdf_sha1": "1b22e5321747", "answer_pdf_sha1": "27d2bd6acd46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00191', 'bookkeeper', 'bookkeeper-moex-113-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '加值型營業人申報之當期營業稅額若為溢付稅額，原則上留抵次期之應納稅額，但若為下列何種情形 者，可由主管稽徵機關查明後退還之？', '["因進口貨物而溢付之營業稅額", "因取得固定資產而溢付之營業稅額", "因勞軍購買之貨物而溢付之營業稅額", "因購買再保險之國外勞務而溢付之營業稅額"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:19+00:00", "source_pdf_sha1": "1b22e5321747", "answer_pdf_sha1": "27d2bd6acd46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00192', 'bookkeeper', 'bookkeeper-moex-113-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', 'A公司為加值型營業人，今年9-10月之內銷銷售額2,000萬元，外銷銷售額為1,000萬元（經海關出 口）；國內進貨1,000萬元，稅額50萬元（取得統一發票扣抵聯）；另購入固定資產500萬元，稅額 25萬元（取得統一發票扣抵聯），以及支付國外專利權利金500萬元，專供經營應稅貨物或勞務之用。 請計算A公司今年9-10月申報之營業稅額若干？', '["應納稅額25萬元", "應納稅額50萬元", "該期無應納稅額", "可退稅50萬元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:19+00:00", "source_pdf_sha1": "1b22e5321747", "answer_pdf_sha1": "27d2bd6acd46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00193', 'bookkeeper', 'bookkeeper-moex-113-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '根據加值型及非加值型營業稅法，下列何者免予繳納營業稅？', '["保稅貨物自保稅區進入中華民國境內之其他地區", "加值型營業人購買專供經營應稅貨物或勞務的國外勞務", "營業人委託他人代銷貨物", "營業人將解散或廢止營業時所餘存之貨物，分配與股東或出資人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:19+00:00", "source_pdf_sha1": "1b22e5321747", "answer_pdf_sha1": "27d2bd6acd46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00194', 'bookkeeper', 'bookkeeper-moex-113-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '甲為兼營應稅及免稅銷售的營業人，113年9月至10月購進貨物1,200萬元，支付進項稅額60萬元， 進項稅額中有10萬元是購進自用乘人小汽車，另有20萬元是對政府的捐獻。同期銷售應稅貨物2,400 萬元，銷項稅額120萬元，銷售免稅貨物1,600萬元，其中1,000萬元為土地價額，故進項稅額不得 扣抵銷項稅額比例為20%。試問甲營業人當期應納稅額為多少？', '["96萬元", "88萬元", "80萬元", "72萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:19+00:00", "source_pdf_sha1": "1b22e5321747", "answer_pdf_sha1": "27d2bd6acd46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00195', 'bookkeeper', 'bookkeeper-moex-113-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '根據加值型及非加值型營業稅法與其施行細則，有關營業稅免稅與零稅率的敘述，下列敘述何者正', '["零稅率表示銷售貨物或勞務所適用的營業稅率為零，由於銷項稅額為零，如有溢付稅額，得在 退稅限額內由主管稽徵機關查明後退還", "免稅，在銷售階段免徵營業稅，但進項稅額不能扣抵或退 還", "免稅等同於零稅率", "保稅區營業人向課稅區營業人購買機器設備，適用零稅率"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:19+00:00", "source_pdf_sha1": "1b22e5321747", "answer_pdf_sha1": "27d2bd6acd46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00196', 'bookkeeper', 'bookkeeper-moex-113-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '試問下列何種稅籍登記之事項變更，向主管稽徵機關申請變更登記前，無須先繳清稅款或提供擔保？', '["增加資本額", "減少資本額", "營業種類變更", "營業人名稱變更  ⑤負責人變更"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:19+00:00", "source_pdf_sha1": "1b22e5321747", "answer_pdf_sha1": "27d2bd6acd46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00197', 'bookkeeper', 'bookkeeper-moex-113-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '根據加值型及非加值型營業稅法，關於營業稅的課稅與減免範圍，下列敘述何者錯誤？', '["銷售免稅貨物或勞務之營業人，得申請財政部核准放棄適用免稅規定，依加值型計算營業稅額", "營業人介紹國內營業人向國外廠商進口原料等，取得之外匯佣金收入，非屬零稅率之適用範圍", "保稅貨物自國外進入保稅區，其應徵之營業稅由海關代徵", "國際運輸事業自我國境內載運客貨出境者，屬在中華民國境內銷售勞務，必須課徵營業稅。但若該 國際運輸事業所屬的國家，對我國國際運輸事業給予零稅率或免徵類似稅捐，則可以適用零稅率"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:19+00:00", "source_pdf_sha1": "1b22e5321747", "answer_pdf_sha1": "27d2bd6acd46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00198', 'bookkeeper', 'bookkeeper-moex-113-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '適用零稅率的營業人，得申請以每月為一期，於次月15日前，填具規定格式之申報書，檢附退抵稅 款及其他有關文件，向主管稽徵機關申報銷售額、應納或溢付營業稅額，但經核准後多久之內不得申 請變更？', '["同一年度內", "二年內", "三年內", "無限制"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:19+00:00", "source_pdf_sha1": "1b22e5321747", "answer_pdf_sha1": "27d2bd6acd46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 41, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00199', 'bookkeeper', 'bookkeeper-moex-113-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '營業人逾規定申報限期多久時間尚未申報銷售額，主管稽徵機關得依照查得之資料，核定其銷售額及 應納稅額並補徵？', '["30日", "40日", "50日", "60日"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:19+00:00", "source_pdf_sha1": "1b22e5321747", "answer_pdf_sha1": "27d2bd6acd46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 42, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00200', 'bookkeeper', 'bookkeeper-moex-113-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '營業人除依法免用統一發票者外，主管稽徵機關應核定其使用統一發票，由營業人向主管稽徵機關申 請核發統一發票購票證，加蓋統一發票專用章，以憑購用統一發票。但營業人有下列何種情形時，主 管稽徵機關應停止其購買統一發票？', '["涉嫌開立不實統一發票", "無進貨事實虛報進項稅額", "滯欠營業稅未繳清", "開立不實統一發票"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:19+00:00", "source_pdf_sha1": "1b22e5321747", "answer_pdf_sha1": "27d2bd6acd46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 43, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00201', 'bookkeeper', 'bookkeeper-moex-113-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '根據我國統一發票使用辦法之規定，下列有關營業人開立統一發票之敘述，何者正確？', '["境外電商銷售電子勞務與國內自然人，應開立二聯式紙本發票寄送買受人", "開立電子發票之營業人，買受人為非營業人者，應於開立後7日內將統一發票資訊及買受人以財政 部核准載具索取電子發票之載具識別資訊傳輸至平台存證，並應使買受人得於該平台查詢、接收上 開資訊", "營業人發行現金禮券者，由持有人按禮券上所載金額，憑以兌購貨物者，於兌付貨物時開立統一發票", "自動販賣機銷售食品、飲料及收取停車費或自動販賣機已具備自行列印統一發票功能者，應於月底 彙總開立統一發票"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:19+00:00", "source_pdf_sha1": "1b22e5321747", "answer_pdf_sha1": "27d2bd6acd46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 44, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00202', 'bookkeeper', 'bookkeeper-moex-113-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '下列何者同時符合免徵營業稅與免用或免開統一發票？①計程車業  ②依法設立之免稅商店及離島', '["醫院、診所、療養院提供之醫療勞務、藥品、病房之住宿及膳食", "未經加工之生 鮮農、林、漁、牧產物、副產物", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:19+00:00", "source_pdf_sha1": "1b22e5321747", "answer_pdf_sha1": "27d2bd6acd46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 45, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00203', 'bookkeeper', 'bookkeeper-moex-113-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '下列財產移轉的情形，有關贈與稅徵免之敘述，何者錯誤？', '["甲成立信託契約明定信託利益全部之受益人為乙，視為甲將享有信託利益之權利贈與該受益人乙， 應課徵贈與稅", "信託關係存續中，受託人依信託本旨交付信託財產，受託人與受益人間之財產移轉，不課徵贈與稅", "祖母出資6,000萬元為其孫購置不動產，應以該出資額6,000萬元計入祖母之贈與總額，課徵贈與稅", "信託關係存續中，委託人追加信託財產，致增加非委託人享有信託利益之權利者，於追加時，就增 加部分，應課徵贈與稅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:19+00:00", "source_pdf_sha1": "1b22e5321747", "answer_pdf_sha1": "27d2bd6acd46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 46, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00204', 'bookkeeper', 'bookkeeper-moex-113-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '有關遺產稅繳納之相關規定，下列敘述何者正確？', '["以中華民國境內之課徵標的物抵繳遺產稅者，其申請抵繳日之時價較死亡日之時價為低者，其得抵 繳之稅額，從高認定，以死亡日之時價計算抵繳稅額", "遺產稅應納稅額在20萬元以上，納稅義務人確有困難，不能一次繳納現金時，得於納稅期限內， 向該管稽徵機關申請，分12期以內繳納，每期間隔以1個月為限", "遺產稅應納稅額在30萬元以上，納稅義務人確有困難，不能一次繳納現金時，得於納稅期限內， 就現金不足繳納部分申請以在中華民國境內之課徵標的物或納稅義務人所有易於變價及保管之實物一 次抵繳", "遺產稅納稅義務人，應於稽徵機關送達核定納稅通知書之日起6個月內，繳清應納稅款；必要時， 得於限期內申請稽徵機關核准延期6個月"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:19+00:00", "source_pdf_sha1": "1b22e5321747", "answer_pdf_sha1": "27d2bd6acd46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 47, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00205', 'bookkeeper', 'bookkeeper-moex-113-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '甲君於113年8月死亡，其為經常居住於中華民國境內的國民。依據遺產及贈與稅法的規定，下列何', '["甲君自己發明的專利權，價值300萬元", "甲君在國外的銀行存款500 萬元", "甲君於106年10月所繼承且已納遺產稅的財產1,000萬元", "甲君112年12月贈與配偶現 金100萬元  ⑤甲君112年12月贈與姪女現金100萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:19+00:00", "source_pdf_sha1": "1b22e5321747", "answer_pdf_sha1": "27d2bd6acd46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 48, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00206', 'bookkeeper', 'bookkeeper-moex-113-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '下列何種情形須課徵贈與稅？①在請求權時效內無償免除債務  ②提出已支付價款確實證明的二親', '["法人贈與給另一 法人", "以顯著不相當之代價，讓與財產、免除或承擔債務", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:19+00:00", "source_pdf_sha1": "1b22e5321747", "answer_pdf_sha1": "27d2bd6acd46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 49, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
